/**
 * Globals to hold config strings.
 */
let appStrings = {};

/**
 * Get modal elements ensuring reusability.
 *
 * @return {Object} jQuery objects for modal elements.
 */
const getModalElements = () => {
    // Look for both the camelCase id (older) and the dash-separated id (modal_item.mustache).
    let root = $('#phItemModalView, #ph-item-modal-view').first();
    let suffix = 'View';

    if (!root.length) {
        root = $('#phItemModalFilter');
        suffix = 'F';
    }

    return {
        root: root,
        title: $(`#phModalTitle${suffix}`),
        name: $(`#phModalName${suffix}`),
        desc: $(`#phModalDesc${suffix}`),
        imgContainer: $(`#phModalImageContainer${suffix}`),
        xp: $(`#phModalXP${suffix}`),
        countBadge: $(`#phModalCountBadge${suffix}`),
        date: $(`#phModalDate${suffix}`),
        dateContainer: $(`#phModalDateContainer${suffix}`),
        dropStats: $(`#phModalDropStats${suffix}`),
        dropProgress: $(`#phModalDropProgress${suffix}`),
        dropCooldown: $(`#phModalDropCooldown${suffix}`)
    };
};

/**
 * Updates the stash (recent items) in the sidebar.
 *
 * @param {Object} itemData
 */
const updateStash = (itemData) => {
    const stashes = $('.ph-sidebar-stash, .ph-widget-stash');

    stashes.each(function() {
        const stash = $(this);
        stash.closest('.ph-stash-wrapper').removeClass('d-none').show();
        stash.find('.text-muted, span.small').remove();

        // Check for duplicate items by name and remove them.
        stash.children().filter((i, el) => $(el).attr('data-name') === itemData.name).remove();

        const isImage = String(itemData.isimage) === '1';
        let contentHtml = '';

        if (isImage) {
            contentHtml = `<img src="${itemData.image}" alt="" class="ph-mini-item-img rounded-0">`;
        } else {
            contentHtml = `<span class="ph-emoji" aria-hidden="true">${itemData.image}</span>`;
        }

        const newItem = $('<div>', {
            'class': 'ph-mini-item ph-item-trigger',
            'role': 'button',
            'tabindex': '0',
            'data-name': itemData.name,
            'data-xp': itemData.xp + ' ' + (appStrings.xp || 'XP'),
            'data-image': itemData.image,
            'data-isimage': itemData.isimage,
            'data-date': itemData.date,
            'data-timestamp': itemData.timestamp || 0,
            'title': itemData.name,
            'aria-label': itemData.name
        });

        newItem.append(`<div class="d-none ph-item-description-content">${itemData.description || ''}</div>`);
        newItem.append(contentHtml);

        newItem.hide().prependTo(stash).fadeIn();

        // Limit items in stash to 6 for both widget and sidebar.
        const limit = 6;
        if (stash.children('.ph-mini-item').length > limit) {
            stash.children('.ph-mini-item').last().remove();
        }
    });
};

/**
 * Updates the Player HUD sidebar with new stats.
 *
 * @param {Object} data Game data from server.
 * @param {Object|null} itemData Collected item data.
 */
const updateHud = (data, itemData) => {
    const containers = $('.playerhud-widget-container, .block_playerhud_sidebar');

    containers.each(function() {
        const container = $(this);

        // Update Level Classes.
        const tierRegex = /(^|\s)ph-lvl-tier-\S+/g;
        const removeTierClasses = (idx, className) => (className.match(tierRegex) || []).join(' ');

        if (container.hasClass('playerhud-widget-container')) {
            container.removeClass(removeTierClasses).addClass(data.level_class);
        }

        container.find('.ph-sidebar-grid, .progress-bar, .badge').each(function() {
            $(this).removeClass(removeTierClasses).addClass(data.level_class);
        });

        // Update Progress Bar.
        const progressBar = container.find('.progress-bar');
        progressBar.css('width', `${data.progress}%`).attr('aria-valuenow', data.progress);
        progressBar.find('.ph-progress-text').text(`${data.progress}%`);

        // Update Level Badge
        const levelBadge = container.find('.badge').filter(function() {
            const cls = $(this).attr('class') || '';
            return cls.match(/ph-lvl-tier-/) && cls.indexOf('rounded-pill') === -1 && cls.indexOf('ph-badge-ghost') === -1;
        });
        if (levelBadge.length) {
            const labelText = appStrings.level || 'Level';
            let lvlString = `${data.level}`;
            if (data.max_levels > 0) {
                lvlString += `/${data.max_levels}`;
            }
            levelBadge.text(`${labelText} ${lvlString}`);
        }

        // Update XP Text
        const xpBadge = container.find('.badge.rounded-pill').filter(function() {
            const cls = $(this).attr('class') || '';
            return cls.match(/ph-lvl-tier-/);
        });
        if (xpBadge.length) {
            let xpString = `${data.currentxp}`;
            if (data.xp_target > 0) {
                xpString += ` / ${data.xp_target}`;
            }
            xpString += ' XP';
            if (data.is_win) {
                xpString += ' 🏆';
            }
            xpBadge.text(xpString);
        }
    });

    if (itemData) {
        updateStash(itemData);
    }
};

/**
 * Handles the collection button loading state.
 *
 * @param {Object} trigger jQuery element.
 * @param {Boolean} isLoading
 * @param {String} originalHtml
 */
const toggleLoading = (trigger, isLoading, originalHtml = '') => {
    const mode = trigger.attr('data-mode') || 'card';

    if (isLoading) {
        trigger.addClass('disabled').attr('aria-disabled', 'true');
        if (mode === 'card') {
            trigger.css('width', trigger.outerWidth() + 'px');
            trigger.html('<i class="fa fa-spinner fa-spin" aria-hidden="true"></i>');
        } else {
            trigger.addClass('ph-opacity-50').css('pointer-events', 'none');
        }
    } else {
        trigger.removeClass('disabled').removeAttr('aria-disabled');
        if (mode === 'card') {
            trigger.css('width', '');
            trigger.html(originalHtml);
        } else {
            trigger.removeClass('ph-opacity-50').css('pointer-events', 'auto');
        }
    }
};

/**
 * Updates UI for Text or Image mode.
 *
 * @param {Object} trigger The jQuery element.
 * @param {String} mode 'text' or 'image'.
 * @param {Boolean} hasTimer If has cooldown.
 * @param {Boolean} isLimit If limit reached.
 * @param {Object} resp Response data.
 */
const updateTextOrImageUi = (trigger, mode, hasTimer, isLimit, resp) => {
    trigger.removeClass('disabled ph-opacity-50').removeAttr('aria-disabled').css('pointer-events', 'auto');

    if (hasTimer || isLimit) {
        if (mode === 'text') {
            trigger.removeAttr('href').removeClass('ph-action-collect').addClass('ph-item-details-trigger');
            trigger.css({'cursor': 'pointer', 'pointer-events': 'auto', 'opacity': '1'});

            if (isLimit) {
                trigger.addClass('text-success fw-bold')
                    .html(`<i class="fa fa-check" aria-hidden="true"></i> ${trigger.text()}`);
            } else {
                trigger.addClass('ph-text-dimmed')
                    .html(`<span aria-hidden="true">⏳</span> ${trigger.text()} ` +
                          `<small class="ph-timer" data-deadline="${resp.cooldown_deadline}">...</small>`);
            }
        } else {
            const container = trigger.closest('.ph-drop-image-container');
            const imgWrapper = container.find('> div').first();
            trigger.remove();

            container.addClass('ph-item-details-trigger ph-cursor-pointer')
                     .attr({'tabindex': '0', 'role': 'button'});

            if (isLimit) {
                imgWrapper.addClass('ph-state-grayscale');
                container.append('<span class="badge bg-success rounded-circle ph-badge-bottom-right">' +
                    '<i class="fa fa-check" aria-hidden="true"></i></span>');
            } else {
                imgWrapper.addClass('ph-state-dimmed');
                container.append(`<div class="ph-timer badge bg-light text-dark border shadow-sm ph-badge-bottom-center"
                    data-deadline="${resp.cooldown_deadline}" data-no-label="1">...</div>`);
            }
        }
    } else if (mode === 'text') {
        const oldColor = trigger.css('color');
        trigger.css('color', '#198754');
        setTimeout(() => trigger.css('color', oldColor), 1000);
    }
};

/**
 * Updates UI for Card mode.
 *
 * @param {Object} trigger The jQuery element.
 * @param {Boolean} hasTimer If has cooldown.
 * @param {Boolean} isLimit If limit reached.
 * @param {Object} resp Response data.
 * @param {String} originalHtml Original button HTML.
 */
const updateCardUi = (trigger, hasTimer, isLimit, resp, originalHtml) => {
    if (hasTimer) {
        trigger.removeClass('btn-primary ph-action-collect').removeAttr('href');
        const tHtml = `⏳ <span class="ph-timer" data-deadline="${resp.cooldown_deadline}">...</span>`;
        const tBtn = $(`<div class="btn btn-light btn-sm w-100 ph-text-dimmed" tabindex="0">${tHtml}</div>`);
        trigger.replaceWith(tBtn);
        tBtn.focus();
    } else if (isLimit) {
        const collectedText = appStrings.collected || 'Collected';
        trigger.removeClass('btn-primary ph-action-collect')
            .addClass('btn-light text-success disabled border-success')
            .css('cursor', 'default').removeAttr('href')
            .html(`<i class="fa fa-check" aria-hidden="true"></i> ${collectedText}`);
        trigger.closest('.playerhud-item-card').find('.ph-item-details-trigger').focus();
    } else {
        const collectedText = appStrings.collected || 'Collected';
        trigger.removeClass('btn-primary disabled').addClass('btn-success')
            .html(`<i class="fa fa-check" aria-hidden="true"></i> ${collectedText}`).css('width', '');

        setTimeout(() => {
            trigger.removeClass('btn-success').addClass('btn-primary').html(originalHtml);
            trigger.removeAttr('aria-disabled');
            trigger.focus();
        }, 1500);
    }
};

/**
 * Fires at most one celebration overlay for a collection, by priority:
 * beating the game (100%) > level-up > first PlayerCoin. The coin milestone is
 * independent of XP (coins grant none), so it never coincides with the others.
 *
 * @param {Object} resp The ajax response.
 */
const triggerCelebration = (resp) => {
    const filterCfg = window.block_playerhud_filter || {};
    const gameData = resp.game_data || {};
    let celebration = null;

    if (gameData.won && filterCfg.winImg) {
        celebration = {type: 'win', image: filterCfg.winImg};
    } else if (gameData.leveled_up && filterCfg.levelupImg) {
        celebration = {type: 'levelup', level: gameData.level, image: filterCfg.levelupImg};
    } else if (resp.milestone === 'coin' && filterCfg.coinImg) {
        celebration = {type: 'coin', image: filterCfg.coinImg};
    }

    if (celebration) {
        require(['block_playerhud/levelup'], (Levelup) => {
            Levelup.celebrate(celebration);
        });
    }
};

/**
 * Process the collection result UI updates (Orchestrator).
 *
 * @param {Object} trigger The jQuery element.
 * @param {Object} resp The ajax response.
 * @param {String} originalHtml The original HTML.
 * @param {Object} strings Localized strings.
 */
const handleCollectionSuccess = (trigger, resp, originalHtml, strings) => {
    const mode = trigger.attr('data-mode') || 'card';
    const hasTimer = (resp.cooldown_deadline && resp.cooldown_deadline > 0);
    const isLimit = resp.limit_reached;

    if (resp.item_data) {
        let container = trigger.closest('.playerhud-item-card, .ph-drop-image-container, .ph-mini-item');
        if (!container.length) {
            container = trigger;
        }

        // Increment count badge if exists.
        let currentCount = parseInt(container.attr('data-count')) || 0;
        container.attr('data-count', currentCount + 1);
        const card = trigger.closest('.playerhud-item-card');
        if (card.length) {
            card.attr('data-date', resp.item_data.date);
            card.attr('data-timestamp', resp.item_data.timestamp);

            // Update XP attribute in DOM so modal reads the new value.
            card.attr('data-xp', resp.item_data.xp + ' ' + (appStrings.xp || 'XP'));
        }

        if (mode === 'image') {
            trigger.closest('.ph-drop-image-container').attr({
                'data-date': resp.item_data.date,
                'data-timestamp': resp.item_data.timestamp,
                'data-xp': resp.item_data.xp + ' ' + (appStrings.xp || 'XP')
            });
        }
    }

    if (mode === 'text' || mode === 'image') {
        updateTextOrImageUi(trigger, mode, hasTimer, isLimit, resp);
    } else {
        updateCardUi(trigger, hasTimer, isLimit, resp, originalHtml, strings);
    }

    if (resp.game_data) {
        updateHud(resp.game_data, resp.item_data);
    }

    triggerCelebration(resp);
};

/**
 * Helper to safely decode Base64 UTF-8 strings.
 *
 * @param {String} str Base64 string
 * @return {String} Decoded string
 */
const safeB64Decode = (str) => {
    try {
        const binString = window.atob(str);
        const bytes = Uint8Array.from(binString, (m) => m.codePointAt(0));
        return new TextDecoder().decode(bytes);
    } catch (e) {
        return '';
    }
};

/**
 * Opens a floating thumbnail card for the overflow items in the +N stash badge.
 *
 * @param {HTMLElement} trigger The .ph-stash-more element that was clicked.
 */
const openOverflowCard = (trigger) => {
    let items;
    try {
        items = JSON.parse(trigger.dataset.overflow);
    } catch (err) {
        return;
    }
    if (!items || !items.length) {
        return;
    }

    const existing = document.getElementById('ph-overflow-card');
    if (existing) {
        existing.remove();
        if (existing._trigger === trigger) {
            return;
        }
    }

    const card = document.createElement('div');
    card.id = 'ph-overflow-card';
    card.className = 'ph-overflow-card';
    card._trigger = trigger;

    const grid = document.createElement('div');
    grid.className = 'ph-overflow-grid';

    items.forEach(item => {
        const thumb = document.createElement('div');
        thumb.className = 'ph-overflow-thumb';
        thumb.title = item.n;

        if (item.i === 1) {
            const img = document.createElement('img');
            img.src = item.u;
            img.alt = '';
            img.className = 'ph-overflow-img';
            thumb.appendChild(img);
        } else {
            const span = document.createElement('span');
            span.className = 'ph-overflow-emoji';
            span.setAttribute('aria-hidden', 'true');
            span.textContent = item.u;
            thumb.appendChild(span);
        }
        grid.appendChild(thumb);
    });

    card.appendChild(grid);
    document.body.appendChild(card);

    const cr = card.getBoundingClientRect();
    const tr = trigger.getBoundingClientRect();
    let top = tr.top - cr.height - 8;
    let left = tr.left + (tr.width / 2) - (cr.width / 2);

    if (top < 8) {
        top = tr.bottom + 8;
    }
    if (left < 8) {
        left = 8;
    }
    if (left + cr.width > window.innerWidth - 8) {
        left = window.innerWidth - cr.width - 8;
    }

    card.style.top = `${top}px`;
    card.style.left = `${left}px`;

    setTimeout(() => {
        document.addEventListener('click', function dismissOverflow() {
            const c = document.getElementById('ph-overflow-card');
            if (c) {
                c.remove();
            }
            document.removeEventListener('click', dismissOverflow);
        });
        document.addEventListener('keydown', function escOverflow(ev) {
            if (ev.key === 'Escape') {
                const c = document.getElementById('ph-overflow-card');
                if (c) {
                    c.remove();
                }
                document.removeEventListener('keydown', escOverflow);
            }
        });
    }, 0);
};

/**
 * Initialize.
 */
export const init = () => {
    // Initialize synchronously from strings_for_js cache (populated by text_filter.php).
    // M.util.get_string() never throws — returns "[[key,component]]" on cache miss.
    // Handlers are registered synchronously below, so this must never throw.
    appStrings = {
        collected: M.util.get_string('collected', 'block_playerhud'),
        respawntime: M.util.get_string('respawntime', 'block_playerhud'),
        infinite: M.util.get_string('infinite', 'block_playerhud'),
        immediate: M.util.get_string('drops_immediate', 'block_playerhud'),
        singleCollection: M.util.get_string('single_collection', 'block_playerhud'),
        error: M.util.get_string('error_connection', 'block_playerhud'),
        lastCollected: M.util.get_string('last_collected', 'block_playerhud'),
        level: M.util.get_string('level', 'block_playerhud'),
        xp: M.util.get_string('xp', 'block_playerhud'),
        noDescription: M.util.get_string('no_description', 'block_playerhud'),
        confirmTitle: M.util.get_string('confirmation', 'admin'),
        yes: M.util.get_string('yes', 'moodle'),
        cancel: M.util.get_string('cancel', 'moodle'),
    };

    // Async update via Str module for AJAX-fragment contexts (e.g. forum posts with
    // shortcodes) where strings_for_js may not yet have been processed.
    // Wrapped in try/catch: if Str.get_strings is unavailable for any reason (e.g.
    // core/str interop differs between Moodle versions), execution continues and the
    // synchronous M.util values above are used as-is.
    try {
        Str.get_strings([
            {key: 'collected', component: 'block_playerhud'},
            {key: 'respawntime', component: 'block_playerhud'},
            {key: 'infinite', component: 'block_playerhud'},
            {key: 'drops_immediate', component: 'block_playerhud'},
            {key: 'single_collection', component: 'block_playerhud'},
            {key: 'error_connection', component: 'block_playerhud'},
            {key: 'last_collected', component: 'block_playerhud'},
            {key: 'level', component: 'block_playerhud'},
            {key: 'xp', component: 'block_playerhud'},
            {key: 'no_description', component: 'block_playerhud'},
            {key: 'confirmation', component: 'admin'},
            {key: 'yes', component: 'moodle'},
            {key: 'cancel', component: 'moodle'},
        ]).then(([collected, respawntime, infinite, immediate, singleCollection,
                  strError, lastCollected, level, xp, noDescription,
                  confirmTitle, yes, cancel]) => {
            appStrings.collected = collected;
            appStrings.respawntime = respawntime;
            appStrings.infinite = infinite;
            appStrings.immediate = immediate;
            appStrings.singleCollection = singleCollection;
            appStrings.error = strError;
            appStrings.lastCollected = lastCollected;
            appStrings.level = level;
            appStrings.xp = xp;
            appStrings.noDescription = noDescription;
            appStrings.confirmTitle = confirmTitle;
            appStrings.yes = yes;
            appStrings.cancel = cancel;
            return;
        }).catch(() => { /* Keep M.util fallbacks. */ });
    } catch (e) {
        // Str.get_strings unavailable; M.util fallbacks remain active.
    }

    // Modal HTML is delivered via $PAGE->requires->data_for_js (no AMD arg size limit).
    // Injecting from JS into <body> bypasses HTML Purifier and ensures the modal is
    // present before AJAX-loaded forum posts render their drop shortcodes.
    const filterData = window.block_playerhud_filter || {};
    if (filterData.modalsHtml
            && !document.getElementById('phItemModalFilter')
            && !document.getElementById('ph-item-modal-view')
            && !document.getElementById('phItemModalView')) {
        document.body.insertAdjacentHTML('beforeend', filterData.modalsHtml);
    }

    const $filterModal = $('#phItemModalFilter');
    if ($filterModal.length) {
        $filterModal.appendTo('body');
    }

    $('body').off('click.phcollect').on('click.phcollect', '.js-disable-hud', function(e) {
        e.preventDefault();
        const url = $(this).attr('href');
        const msg = $(this).attr('data-confirm-msg');

        Notification.confirm(
            appStrings.confirmTitle,
            msg,
            appStrings.yes,
            appStrings.cancel,
            () => {
                window.location.href = url;
            }
        );
    });

    // Item Details Modal.
    // Also handles .ph-mini-item.ph-item-trigger (widget stash items) when view.js is not
    // loaded — i.e., when the block sidebar is absent on activity pages.
    /* eslint-disable complexity */
    $('body').off('click.phdetails keydown.phdetails')
        .on('click.phdetails keydown.phdetails',
            '.ph-item-details-trigger, .ph-mini-item.ph-item-trigger', function(e) {
        if (e.type === 'keydown' && e.key !== 'Enter' && e.key !== ' ') {
            return;
        }
        e.preventDefault();

        // When the block sidebar is present, view.js is loaded and handles .ph-item-trigger.
        if ($(this).hasClass('ph-item-trigger') && document.querySelector('.block_playerhud_sidebar')) {
            return;
        }

        const trigger = $(this);
        let container = trigger.closest('.playerhud-item-card, .ph-drop-image-container, .ph-mini-item');
        if (!container.length) {
            container = trigger;
        }

        const data = {
            name: container.attr('data-name'),
            descB64: container.attr('data-desc-b64'),
            descDirect: container.find('.ph-item-description-content').html(),
            img: container.attr('data-image'),
            isImg: container.attr('data-isimage'),
            xp: container.attr('data-xp'),
            date: container.attr('data-date'),
            timestamp: container.attr('data-timestamp'),
            count: container.attr('data-count'),
            maxusage: container.attr('data-maxusage'),
            respawntimeStr: container.attr('data-respawntime-str')
        };

        const modalEls = getModalElements();
        if (!modalEls.root.length) {
            return;
        }

        modalEls.name.text(data.name);

        if (data.xp && data.xp !== '0' && String(data.xp).trim() !== '0 XP') {
            const xpStr = String(data.xp);
            if (xpStr.indexOf('???') === -1) {
                const isNum = !isNaN(parseFloat(data.xp)) && isFinite(data.xp);
                // Ensure text contains " XP" if it is just a number.
                const xpText = isNum ? `${data.xp} XP` : data.xp;

                modalEls.xp.text(xpText).removeClass('d-none').show();

                // Force blue color (bg-primary) in filter modal, removing old styles.
                modalEls.xp.removeClass('ph-bg-teal bg-info text-dark').addClass('bg-primary text-white');
            } else {
                modalEls.xp.hide();
            }
        } else {
            modalEls.xp.hide();
        }

        if (modalEls.countBadge.length) {
            modalEls.countBadge.hide();
        }

        let descHtml = '';
        if (data.descDirect && data.descDirect.trim() !== '') {
            descHtml = data.descDirect;
        } else if (data.descB64 && data.descB64.trim() !== '') {
            descHtml = safeB64Decode(data.descB64);
        }

        if (!descHtml || descHtml.trim() === '') {
            const fallbackText = appStrings.noDescription || '- no description -';
            modalEls.desc.empty().append(
                $('<i>', {
                    'class': 'text-muted',
                    text: fallbackText
                })
            );
        } else {
            modalEls.desc.html(descHtml);
        }

        // Show stats if max usage or respawn time exists.
        let showStats = false;

        // Only display Drop stats if it is actually a Drop (Shortcode in text).
        if (data.maxusage !== undefined) {
            const maxUsage = parseInt(data.maxusage, 10);

            // 1. Progress Badge (Infinite or X/Y count).
            if (maxUsage === 0) {
                const textStr = appStrings.infinite || 'Infinite';
                const iconHtml = '<i class="fa fa-infinity me-1" aria-hidden="true"></i>';
                modalEls.dropProgress.html(`${iconHtml}${textStr}`).show();
                showStats = true;
            } else if (!isNaN(maxUsage) && data.count !== undefined) {
                const textStr = appStrings.collected || 'Collected';
                modalEls.dropProgress.text(`${data.count}/${maxUsage} ${textStr}`).show();
                showStats = true;
            } else {
                modalEls.dropProgress.hide();
            }

            // 2. Cooldown Badge (Single, Immediate, or Timer).
            if (maxUsage === 1) {
                const textStr = appStrings.singleCollection || 'Single collection';
                const iconHtml = '<i class="fa fa-lock me-1" aria-hidden="true"></i>';
                modalEls.dropCooldown.html(`${iconHtml}${textStr}`).show();
                showStats = true;
            } else if (data.respawntimeStr && data.respawntimeStr.trim() !== '') {
                const textStr = appStrings.respawntime || 'Cooldown';
                const iconHtml = '<i class="fa fa-clock-o me-1" aria-hidden="true"></i>';
                modalEls.dropCooldown.html(`${iconHtml}${textStr}: ${data.respawntimeStr}`).show();
                showStats = true;
            } else if (maxUsage > 1) {
                const textStr = appStrings.immediate || 'Immediate';
                const iconHtml = '<i class="fa fa-bolt text-warning me-1" aria-hidden="true"></i>';
                modalEls.dropCooldown.html(`${iconHtml}${textStr}`).show();
                showStats = true;
            } else {
                modalEls.dropCooldown.hide();
            }
        }

        if (showStats) {
            modalEls.dropStats.removeClass('ph-display-none d-none').css('display', 'flex');
        } else {
            modalEls.dropStats.hide();
        }

        let formattedDate = data.date;
        if (data.timestamp && data.timestamp > 0) {
            const lang = ($('html').attr('lang') || 'en').replace('_', '-');
            try {
                formattedDate = new Date(parseInt(data.timestamp) * 1000).toLocaleDateString(lang, {
                    day: '2-digit', month: '2-digit', year: '2-digit'
                });
            } catch (err) { /* Ignore */ }
        }

        if (formattedDate) {
            const prefix = appStrings.lastCollected ? `${appStrings.lastCollected} ` : '';
            if (modalEls.dateContainer.length) {
                modalEls.date.text(prefix + formattedDate);
                modalEls.dateContainer.removeClass('d-none');
            } else {
                modalEls.date.find('span').text(prefix + formattedDate);
                modalEls.date.show();
            }
        } else {
            if (modalEls.dateContainer.length) {
                modalEls.dateContainer.addClass('d-none');
            } else {
                modalEls.date.hide();
            }
        }

        modalEls.imgContainer.empty();
        if (String(data.isImg) === '1') {
            modalEls.imgContainer.append($('<img>', {src: data.img, 'class': 'ph-modal-img', alt: ''}));
        } else {
            modalEls.imgContainer.append($('<span>', {
                'class': 'ph-modal-emoji',
                'aria-hidden': 'true',
                text: data.img
            }));
        }

        const modalEl = modalEls.root[0];
        document.body.appendChild(modalEl);
        require(['theme_boost/bootstrap/modal'], function(BootstrapModal) {
            var inst = (BootstrapModal.getInstance && BootstrapModal.getInstance(modalEl))
                || $(modalEl).data('bs.modal')
                || new BootstrapModal(modalEl);
            inst.show();
        });
    });
    /* eslint-enable complexity */

    // Overflow popover: clicking the +N stash badge shows hidden item thumbnails.
    $('body').off('click.phstashmore').on('click.phstashmore', '.ph-stash-more[data-overflow]', function(e) {
        e.stopPropagation();
        openOverflowCard(this);
    });
    $('body').off('keydown.phstashmore').on('keydown.phstashmore', '.ph-stash-more[data-overflow]', function(e) {
        if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault();
            openOverflowCard(this);
        }
    });

    // ACTION: COLLECT ITEM.
    $('body').off('click.phaction').on('click.phaction', '.ph-action-collect', function(e) {
        e.preventDefault();
        const trigger = $(this);

        if (trigger.hasClass('disabled') || trigger.attr('aria-disabled')) {
            return;
        }

        const originalHtml = trigger.html();
        toggleLoading(trigger, true);

        const href = trigger.attr('href');
        if (!href) {
            toggleLoading(trigger, false, originalHtml);
            return;
        }

        const urlObj = new URL(href, window.location.href);
        const params = {
            instanceid: parseInt(urlObj.searchParams.get('instanceid')),
            dropid: parseInt(urlObj.searchParams.get('dropid')),
            courseid: parseInt(urlObj.searchParams.get('courseid'))
        };

        if (isNaN(params.instanceid) || isNaN(params.dropid) || isNaN(params.courseid)) {
            toggleLoading(trigger, false, originalHtml);
            return;
        }

        Ajax.call([{
            methodname: 'block_playerhud_collect_item',
            args: params
        }])[0].then((resp) => {
            if (resp.success) {
                handleCollectionSuccess(trigger, resp, originalHtml, appStrings);
                return;
            }

            toggleLoading(trigger, false, originalHtml);
            // eslint-disable-next-line consistent-return, promise/no-nesting
            return Str.get_strings([
                {key: 'error', component: 'core'},
                {key: 'ok', component: 'core'}
            ]).then((strs) => {
                return Notification.alert(strs[0], resp.message, strs[1]);
            });

        }).catch((ex) => {
            toggleLoading(trigger, false, originalHtml);
            Notification.exception(ex);
        });
    });
};
